using namespace kth::consensus;

// Map kth forks to consensus verify_flags for BCHN.
// Mirrors BCHN's test_individual_opcode_counts flags:
//   STANDARD_SCRIPT_VERIFY_FLAGS | SCRIPT_ENABLE_TOKENS | SCRIPT_ENABLE_P2SH_32
//   | SCRIPT_ENABLE_MAY2025 | SCRIPT_VM_LIMITS_STANDARD | SCRIPT_64_BIT_INTEGERS
//   | SCRIPT_NATIVE_INTROSPECTION
unsigned int script_flags_to_verify_flags(script_flags_t active_flags, bool standard) {
    unsigned int flags = 0;
    if (active_flags & script_flags::bch_vm_limits) {
        flags |= verify_flags_enable_may2025;
        if (standard) {
            flags |= verify_flags_enable_vm_limits_standard;
        }
    }
    if (active_flags & script_flags::bch_minimaldata) {
        flags |= verify_flags_minimaldata;
    }
    if (active_flags & script_flags::bch_64bit_integers) {
        flags |= verify_flags_64_bit_integers;
    }
    if (active_flags & script_flags::bch_native_introspection) {
        flags |= verify_flags_native_introspection;
    }
    if (active_flags & script_flags::bch_p2sh_32) {
        flags |= verify_flags_enable_p2sh_32;
    }
    if (active_flags & script_flags::bch_tokens) {
        flags |= verify_flags_enable_tokens;
    }
    if (active_flags & script_flags::bch_input_sigchecks) {
        flags |= verify_flags_input_sigchecks;
    }
    if (active_flags & script_flags::bch_enforce_sigchecks) {
        flags |= verify_flags_enforce_sigchecks;
    }
    return flags;
}

struct consensus_result {
    verify_result_type result;
    int sig_checks;
    int64_t op_cost;
    int64_t hash_iters;
    data_stack stack;
};

consensus_result eval_consensus(data_stack initial_stack, script const& scr, unsigned int flags) {
    auto const script_bytes = scr.to_data(false);
    auto stack = initial_stack;
    script_eval_metrics metrics{};
    auto const result = eval_script_with_metrics(
        script_bytes.data(), script_bytes.size(),
        flags, stack, metrics);
    return {result, metrics.sig_checks, metrics.op_cost, metrics.hash_digest_iterations, std::move(stack)};
}

#endif // WITH_CONSENSUS

// ─── Unified check: native + consensus (when available) ──────────────────────

// Run kth native interpreter and check metrics against expected values.
// When WITH_CONSENSUS is defined, also run BCHN and cross-check both VMs.
void check_eval(data_stack const& initial, script const& scr, script_flags_t flags,
                std::optional<data_stack> const& expected_stack,
                int expected_sig_checks, int64_t expected_hash_iters,
                int64_t expected_op_cost_std,
                int64_t expected_op_cost_nonstd = -1) {

    if (expected_op_cost_nonstd < 0) expected_op_cost_nonstd = expected_op_cost_std;

    // --- kth native ---
    auto [ec, n_sc, n_hi, n_oc, n_std, n_nonstd, n_stack] = eval_native(initial, scr, flags);
    if (ec) {
        UNSCOPED_INFO("native error: " << ec.message() << " (" << ec.value() << ")");
    }
    if (expected_stack) {
        CHECK(n_stack == *expected_stack);
    }
    CHECK(n_sc == expected_sig_checks);
    CHECK(n_hi == expected_hash_iters);
    CHECK(n_std == expected_op_cost_std);
    CHECK(n_nonstd == expected_op_cost_nonstd);

#ifdef WITH_CONSENSUS
    // --- BCHN consensus (standard) ---
    auto const flags_std = script_flags_to_verify_flags(flags, true);
    auto [c_result_s, c_sc_s, c_oc_s, c_hi_s, c_stack_s] = eval_consensus(initial, scr, flags_std);
    if (expected_stack) {
        CHECK(c_stack_s == *expected_stack);
    }
    CHECK(c_sc_s == expected_sig_checks);
    CHECK(c_hi_s == expected_hash_iters);
    int64_t const c_composite_std = c_oc_s + c_hi_s * 192 + int64_t(c_sc_s) * 26'000;
    CHECK(c_composite_std == expected_op_cost_std);

    // --- BCHN consensus (non-standard) ---
    auto const flags_nonstd = script_flags_to_verify_flags(flags, false);
    auto [c_result_n, c_sc_n, c_oc_n, c_hi_n, c_stack_n] = eval_consensus(initial, scr, flags_nonstd);
    if (expected_stack) {
        CHECK(c_stack_n == *expected_stack);
    }
    CHECK(c_sc_n == expected_sig_checks);
    CHECK(c_hi_n == expected_hash_iters);
    int64_t const c_composite_nonstd = c_oc_n + c_hi_n * 64 + int64_t(c_sc_n) * 26'000;
    CHECK(c_composite_nonstd == expected_op_cost_nonstd);

    // --- Cross-check: native vs consensus ---
    CHECK(n_sc == c_sc_s);
    CHECK(n_hi == c_hi_s);
    CHECK(n_oc == c_oc_s);
    CHECK(n_stack == c_stack_s);
#endif // WITH_CONSENSUS
}

// ─── Unified check for expected-failure tests ───────────────────────────────

// Run kth native interpreter and verify execution FAILS.
// When WITH_CONSENSUS is defined, also run BCHN and cross-check both VMs.
// BCHN checks: r == false, stack == expectedStack, metrics match.
void check_eval_fail(data_stack const& initial, script const& scr, script_flags_t flags,
                     data_stack const& expected_stack,
                     int expected_sig_checks, int64_t expected_hash_iters,
                     int64_t expected_op_cost_std,
                     int64_t expected_op_cost_nonstd = -1) {

    if (expected_op_cost_nonstd < 0) expected_op_cost_nonstd = expected_op_cost_std;

    // --- kth native ---
    auto [ec, n_sc, n_hi, n_oc, n_std, n_nonstd, n_stack] = eval_native(initial, scr, flags);
    UNSCOPED_INFO("native error: " << ec.message() << " (" << ec.value() << ")");
    CHECK(ec);  // Must be an error (non-zero)
    CHECK(n_stack == expected_stack);
    CHECK(n_sc == expected_sig_checks);
    CHECK(n_hi == expected_hash_iters);
    CHECK(n_std == expected_op_cost_std);
    CHECK(n_nonstd == expected_op_cost_nonstd);

#ifdef WITH_CONSENSUS
    // --- BCHN consensus (standard) ---
    auto const flags_std = script_flags_to_verify_flags(flags, true);
    auto [c_result_s, c_sc_s, c_oc_s, c_hi_s, c_stack_s] = eval_consensus(initial, scr, flags_std);
    CHECK(c_result_s != verify_result_type::verify_result_eval_true);  // Must fail
    CHECK(c_stack_s == expected_stack);
    CHECK(c_sc_s == expected_sig_checks);
    CHECK(c_hi_s == expected_hash_iters);
    int64_t const c_composite_std = c_oc_s + c_hi_s * 192 + int64_t(c_sc_s) * 26'000;
    CHECK(c_composite_std == expected_op_cost_std);

    // --- BCHN consensus (non-standard) ---
    auto const flags_nonstd = script_flags_to_verify_flags(flags, false);
    auto [c_result_n, c_sc_n, c_oc_n, c_hi_n, c_stack_n] = eval_consensus(initial, scr, flags_nonstd);
    CHECK(c_result_n != verify_result_type::verify_result_eval_true);  // Must fail
    CHECK(c_stack_n == expected_stack);
    CHECK(c_sc_n == expected_sig_checks);
    CHECK(c_hi_n == expected_hash_iters);
    int64_t const c_composite_nonstd = c_oc_n + c_hi_n * 64 + int64_t(c_sc_n) * 26'000;
    CHECK(c_composite_nonstd == expected_op_cost_nonstd);

    // --- Cross-check: native vs consensus ---
    CHECK(n_sc == c_sc_s);
    CHECK(n_hi == c_hi_s);
    CHECK(n_oc == c_oc_s);
    CHECK(n_stack == c_stack_s);
#endif // WITH_CONSENSUS
}

// ─── Transaction context for introspection tests ─────────────────────────────

// Deserialize a transaction from raw hex bytes.
chain::transaction deserialize_tx(data_chunk const& raw) {
    byte_reader reader(raw);
    auto result = chain::transaction::from_data(reader, true);
    REQUIRE(result.has_value());
    return std::move(*result);
}

// Build a transaction with UTXO caches set from previous transactions.
// This sets up the prevout validation cache needed by introspection opcodes.
struct tx_context {
    chain::transaction tx;
    uint32_t input_index;
};

tx_context build_tx_context(data_chunk const& tx_raw,
                            data_chunk const& prev_tx0_raw,
                            data_chunk const& prev_tx1_raw,
                            uint32_t input_index) {
    auto tx = deserialize_tx(tx_raw);
    auto prev_tx0 = deserialize_tx(prev_tx0_raw);
    auto prev_tx1 = deserialize_tx(prev_tx1_raw);

    REQUIRE(tx.inputs().size() == 2);

    // Set UTXO cache for input 0: prevTx0.outputs[tx.inputs[0].prevout.index]
    auto const idx0 = tx.inputs()[0].previous_output().index();
    REQUIRE(idx0 < prev_tx0.outputs().size());
    tx.inputs()[0].previous_output().validation.cache = prev_tx0.outputs()[idx0];

    // Set UTXO cache for input 1: prevTx1.outputs[tx.inputs[1].prevout.index]
    auto const idx1 = tx.inputs()[1].previous_output().index();
    REQUIRE(idx1 < prev_tx1.outputs().size());
    tx.inputs()[1].previous_output().validation.cache = prev_tx1.outputs()[idx1];

    return {std::move(tx), input_index};
}

// Run the native interpreter with a real transaction context.
eval_result eval_native_ctx(data_stack initial_stack, script const& scr, script_flags_t flags,
                            tx_context const& ctx) {
    auto const utxo_value = ctx.tx.inputs()[ctx.input_index].previous_output().validation.cache.value();
    program prog(scr, ctx.tx, ctx.input_index, flags, std::move(initial_stack), utxo_value);
    auto const ec = interpreter::run(prog);
    auto& m = prog.get_metrics();

    int64_t const std_cost = m.op_cost()
        + m.hash_digest_iterations() * machine::may2025::hash_iter_op_cost_factor(true)
        + int64_t(m.sig_checks()) * ::kth::may2025::sig_check_cost_factor;
    int64_t const nonstd_cost = m.op_cost()
        + m.hash_digest_iterations() * machine::may2025::hash_iter_op_cost_factor(false)
        + int64_t(m.sig_checks()) * ::kth::may2025::sig_check_cost_factor;

    data_stack result_stack;
    for (size_t i = prog.size(); i > 0; --i) {
        result_stack.push_back(prog.item(i - 1));
    }

    return {
        ec,
        static_cast<int>(m.sig_checks()),
        static_cast<int64_t>(m.hash_digest_iterations()),
        static_cast<int64_t>(m.op_cost()),
        std_cost,
        nonstd_cost,
        std::move(result_stack),
    };
}

// Check evaluation with transaction context (for introspection opcode tests).
void check_eval_ctx(data_stack const& initial, script const& scr, script_flags_t flags,
                    tx_context const& ctx,
                    std::optional<data_stack> const& expected_stack,
                    int expected_sig_checks, int64_t expected_hash_iters,
                    int64_t expected_op_cost_std,
                    int64_t expected_op_cost_nonstd = -1) {

    if (expected_op_cost_nonstd < 0) expected_op_cost_nonstd = expected_op_cost_std;

    // --- kth native with context ---
    auto [ec, n_sc, n_hi, n_oc, n_std, n_nonstd, n_stack] = eval_native_ctx(initial, scr, flags, ctx);
    if (ec) {
        UNSCOPED_INFO("native error: " << ec.message() << " (" << ec.value() << ")");
    }
    CHECK( ! ec);
    if (expected_stack) {
        CHECK(n_stack == *expected_stack);
    }
    CHECK(n_sc == expected_sig_checks);
    CHECK(n_hi == expected_hash_iters);
    CHECK(n_std == expected_op_cost_std);
    CHECK(n_nonstd == expected_op_cost_nonstd);
}

